import React, { useState, useEffect } from 'react';
import { 
  Container, 
  Typography, 
  Box, 
  Paper, 
  Grid, 
  Button, 
  Card, 
  CardContent, 
  CardActions,
  Dialog,
  DialogTitle,
  DialogContent,
  DialogActions,
  TextField,
  FormControl,
  InputLabel,
  Select,
  MenuItem,
  CircularProgress,
  Alert,
  IconButton,
  Tooltip
} from '@mui/material';
import { 
  AccountBalanceWallet, 
  ContentCopy, 
  Add,
  Visibility,
  VisibilityOff
} from '@mui/icons-material';
import api from '../utils/api';
import { useAuth } from '../context/AuthContext';

const Wallets = () => {
  const { currentUser } = useAuth();
  const [wallets, setWallets] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [openDialog, setOpenDialog] = useState(false);
  const [walletFormData, setWalletFormData] = useState({
    user_id: null,
    name: '',
    currency: 'USD',
  });
  const [formError, setFormError] = useState('');
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [showPrivateKeys, setShowPrivateKeys] = useState({});
  const [copySuccess, setCopySuccess] = useState('');

  const currencies = ['USD', 'EUR', 'GBP', 'CAD', 'JPY', 'USDC', 'USDT', 'ETH', 'BTC'];

  useEffect(() => {
    fetchWallets();
  }, []);

  useEffect(() => {
    // Update user_id in form data when currentUser changes
    if (currentUser && currentUser.id) {
      setWalletFormData(prev => ({
        ...prev,
        user_id: currentUser.id
      }));
    }
  }, [currentUser]);

  const fetchWallets = async () => {
    setLoading(true);
    setError(null);

    try {
      console.log('Fetching wallets...');
      let walletsData = [];

      // First try to get wallets for the specific user if we have a user ID
      if (currentUser && currentUser.id) {
        try {
          const response = await api.get(`/wallet/${currentUser.id}`);
          console.log('User wallet response:', response.data);
          if (Array.isArray(response.data)) {
            walletsData = response.data;
          } else if (response.data) {
            // If it's a single wallet or has a different structure
            walletsData = [response.data];
          }
        } catch (userWalletErr) {
          console.warn('Error fetching user-specific wallet, trying general endpoint:', userWalletErr);
        }
      }

      // If we couldn't get user-specific wallets or they were empty, try the general endpoint
      if (walletsData.length === 0) {
        try {
          const allWalletsResponse = await api.get('/wallet/');
          console.log('All wallets response:', allWalletsResponse.data);
          if (Array.isArray(allWalletsResponse.data)) {
            walletsData = allWalletsResponse.data;
          } else if (allWalletsResponse.data) {
            walletsData = [allWalletsResponse.data];
          }
        } catch (allWalletsErr) {
          console.error('Error fetching all wallets:', allWalletsErr);
          throw allWalletsErr; // Re-throw to be caught by the outer catch
        }
      }

      console.log('Final wallets data:', walletsData);
      setWallets(walletsData);
    } catch (err) {
      console.error('Error fetching wallets:', err);
      setError('Failed to load wallets. Please try again.');
    } finally {
      setLoading(false);
    }
  };

  const handleCreateWallet = async () => {
    setFormError('');
    setIsSubmitting(true);

    try {
      // Validate form data
      if (!walletFormData.name.trim()) {
        setFormError('Wallet name is required');
        setIsSubmitting(false);
        return;
      }

      // Ensure user_id is set
      if (!walletFormData.user_id && currentUser && currentUser.id) {
        walletFormData.user_id = currentUser.id;
      }

      console.log('Creating wallet with data:', walletFormData);
      const response = await api.post('/wallet/', walletFormData);
      console.log('Wallet creation response:', response.data);

      if (response.data) {
        // Add the new wallet to the state
        setWallets([...wallets, response.data]);
        setOpenDialog(false);
        resetFormData();
      } else {
        throw new Error('Invalid response from server');
      }
    } catch (err) {
      console.error('Error creating wallet:', err);
      setFormError(err.response?.data?.detail || 'Failed to create wallet. Please try again.');
    } finally {
      setIsSubmitting(false);
    }
  };

  const resetFormData = () => {
    setWalletFormData({
      user_id: currentUser?.id || null,
      name: '',
      currency: 'USD',
    });
  };

  const handleDialogClose = () => {
    setOpenDialog(false);
    resetFormData();
    setFormError('');
  };

  const handleInputChange = (e) => {
    const { name, value } = e.target;
    setWalletFormData({
      ...walletFormData,
      [name]: value
    });
  };

  const togglePrivateKeyVisibility = (walletId) => {
    setShowPrivateKeys({
      ...showPrivateKeys,
      [walletId]: !showPrivateKeys[walletId]
    });
  };

  const copyToClipboard = (text, type) => {
    navigator.clipboard.writeText(text).then(
      () => {
        setCopySuccess(`${type} copied!`);
        setTimeout(() => setCopySuccess(''), 2000);
      },
      () => {
        setCopySuccess('Failed to copy');
      }
    );
  };

  const formatCurrency = (amount, currency = 'USD') => {
    return new Intl.NumberFormat('en-US', {
      style: 'currency',
      currency
    }).format(amount || 0);
  };

  if (loading) {
    return (
      <Box display="flex" justifyContent="center" alignItems="center" minHeight="80vh">
        <CircularProgress />
      </Box>
    );
  }

  return (
    <Container maxWidth="lg">
      <Box sx={{ mt: 4, mb: 4 }}>
        <Paper sx={{ p: 3 }}>
          <Box display="flex" justifyContent="space-between" alignItems="center" mb={3}>
            <Typography variant="h4" component="h1">
              Your Wallets
            </Typography>
            <Button 
              variant="contained" 
              startIcon={<Add />}
              onClick={() => setOpenDialog(true)}
            >
              New Wallet
            </Button>
          </Box>

          {error && (
            <Alert severity="error" sx={{ mb: 3 }}>
              {error}
            </Alert>
          )}

          {copySuccess && (
            <Alert severity="success" sx={{ mb: 3 }}>
              {copySuccess}
            </Alert>
          )}

          {wallets.length === 0 ? (
            <Box textAlign="center" py={5}>
              <AccountBalanceWallet sx={{ fontSize: 60, color: 'text.secondary', mb: 2 }} />
              <Typography variant="h6" gutterBottom>
                No Wallets Found
              </Typography>
              <Typography variant="body1" color="text.secondary" paragraph>
                You haven't created any wallets yet. Create your first wallet to start sending and receiving payments.
              </Typography>
              <Button 
                variant="contained" 
                startIcon={<Add />}
                onClick={() => setOpenDialog(true)}
              >
                Create Your First Wallet
              </Button>
            </Box>
          ) : (
            <Grid container spacing={3}>
              {wallets.map((wallet, index) => (
                <Grid item xs={12} sm={6} md={4} key={wallet.id || index}>
                  <Card sx={{ height: '100%', display: 'flex', flexDirection: 'column' }}>
                    <CardContent sx={{ flexGrow: 1 }}>
                      <Typography variant="h6" gutterBottom>
                        {currentUser.username}'s Wallet
                      </Typography>

                      <Box sx={{ mt: 2 }}>
                        <Typography variant="caption" color="text.secondary">
                          Fiat Balance
                        </Typography>
                        <Typography variant="h5" fontWeight="bold">
                          {formatCurrency(wallet.fiat_balance, wallet.base_currency || wallet.currency)}
                        </Typography>
                        <Typography variant="body2" color="text.secondary" gutterBottom>
                          Base Currency: {wallet.base_currency || wallet.currency}
                        </Typography>

                        <Typography variant="caption" color="text.secondary" sx={{ mt: 1, display: 'block' }}>
                          Stablecoin Balance
                        </Typography>
                        <Typography variant="h6" fontWeight="medium">
                          {formatCurrency(wallet.stablecoin_balance, 'USDT')} USDT
                        </Typography>
                      </Box>

                      {wallet.blockchain_address && (
                        <Box sx={{ mt: 2 }}>
                          <Typography variant="caption" color="text.secondary">
                            Blockchain Address
                          </Typography>
                          <Box sx={{ display: 'flex', alignItems: 'center', mt: 0.5 }}>
                            <Typography 
                              variant="body2" 
                              sx={{ 
                                maxWidth: '80%', 
                                overflow: 'hidden', 
                                textOverflow: 'ellipsis',
                                mr: 1
                              }}
                            >
                              {showPrivateKeys[wallet.id] ? wallet.blockchain_address : 
                                wallet.blockchain_address?.substring(0, 10) + '...' + 
                                wallet.blockchain_address?.substring(wallet.blockchain_address.length - 6)}
                            </Typography>
                            <Tooltip title={showPrivateKeys[wallet.id] ? "Hide Address" : "Show Full Address"}>
                              <IconButton 
                                size="small" 
                                onClick={() => togglePrivateKeyVisibility(wallet.id)}
                              >
                                {showPrivateKeys[wallet.id] ? <VisibilityOff fontSize="small" /> : <Visibility fontSize="small" />}
                              </IconButton>
                            </Tooltip>
                            <Tooltip title="Copy Address">
                              <IconButton 
                                size="small"
                                onClick={() => copyToClipboard(wallet.blockchain_address, "Blockchain address")}
                              >
                                <ContentCopy fontSize="small" />
                              </IconButton>
                            </Tooltip>
                          </Box>
                        </Box>
                      )}
                    </CardContent>
                    <CardActions>
                      <Button size="small" color="primary">
                        Deposit
                      </Button>
                      <Button size="small" color="primary">
                        Send
                      </Button>
                    </CardActions>
                  </Card>
                </Grid>
              ))}
            </Grid>
          )}
        </Paper>
      </Box>

      {/* Create Wallet Dialog */}
      <Dialog open={openDialog} onClose={handleDialogClose} maxWidth="sm" fullWidth>
        <DialogTitle>Create New Wallet</DialogTitle>
        <DialogContent>
          {formError && (
            <Alert severity="error" sx={{ mb: 2 }}>
              {formError}
            </Alert>
          )}

          <TextField
            margin="dense"
            name="name"
            label="Wallet Name"
            type="text"
            fullWidth
            variant="outlined"
            value={walletFormData.name}
            onChange={handleInputChange}
            required
            sx={{ mb: 2 }}
          />

          <FormControl fullWidth variant="outlined" sx={{ mb: 2 }}>
            <InputLabel>Currency</InputLabel>
            <Select
              name="currency"
              value={walletFormData.currency}
              onChange={handleInputChange}
              label="Currency"
            >
              {currencies.map((currency) => (
                <MenuItem key={currency} value={currency}>
                  {currency}
                </MenuItem>
              ))}
            </Select>
          </FormControl>
        </DialogContent>
        <DialogActions>
          <Button onClick={handleDialogClose}>Cancel</Button>
          <Button 
            onClick={handleCreateWallet} 
            variant="contained" 
            disabled={isSubmitting}
          >
            {isSubmitting ? 'Creating...' : 'Create Wallet'}
          </Button>
        </DialogActions>
      </Dialog>
    </Container>
  );
};

export default Wallets;
